(function() {
    const $ = window.jQuery;
    const HAS_MSG = /\((out|in)\)/i;
    const TAG_RE = /^\s*\((out|in)\)\s*(.*)/i;
    const CSS_ID = 'msgbubble-css';
    const CSS = `.msg-b{padding:9px 14px;border-radius:16px;font-size:0.9em;line-height:1.5;max-width:80%;word-wrap:break-word;text-align:left;position:relative;opacity:0;transform:translateY(12px) scale(0.97);animation:msgIn 0.45s ease forwards;margin:3px 0;display:table}
.msg-b.out{margin-right:auto;background:rgba(220,220,225,0.9);color:#1a1a1a;border:1px solid rgba(255,255,255,0.15);border-bottom-left-radius:4px}
.msg-b.in{margin-left:auto;background:linear-gradient(135deg,#4A6FA5,#3B5998);color:#f0f2f5;border:1px solid rgba(74,111,165,0.4);border-bottom-right-radius:4px;box-shadow:0 2px 8px rgba(59,89,152,0.3)}
@keyframes msgIn{to{opacity:1;transform:translateY(0) scale(1)}}`;

    let TH = null;
    function esc(s) { return (s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

    function renderVisual(messageId) {
        if (!TH) return;
        const msgs = TH.getChatMessages(messageId);
        if (!msgs || !msgs.length || !msgs[0].message) return;
        const raw = msgs[0].message;
        if (!HAS_MSG.test(raw)) return;

        const $mes = TH.retrieveDisplayedMessage(messageId);
        if (!$mes || !$mes.length) return;
        const $target = $mes.find('.mes_text').length ? $mes.find('.mes_text') : $mes;
        let html = $target.html();
        if (!html || html.indexOf('class="msg-b') >= 0) return;

        const lines = raw.split('\n');
        const replacements = [];
        let bubbleIdx = 0;
        for (let i = 0; i < lines.length; i++) {
            const m = lines[i].match(TAG_RE);
            if (!m) continue;
            const type = m[1].toLowerCase();
            const text = m[2].trim();
            if (!text) continue;
            const d = (bubbleIdx * 0.25).toFixed(2);
            const bubble = '<div class="msg-b ' + type + '" style="animation-delay:' + d + 's">' + esc(text) + '</div>';
            replacements.push({ tag: '(' + m[1] + ')', text: text, bubble: bubble });
            bubbleIdx++;
        }
        if (replacements.length === 0) return;

        let changed = false;
        for (let i = replacements.length - 1; i >= 0; i--) {
            const r = replacements[i];
            const needle = r.tag + ' ' + r.text;
            const needleEsc = esc(r.tag) + ' ' + esc(r.text);
            let idx = html.indexOf(needle);
            if (idx < 0) idx = html.indexOf(needleEsc);
            if (idx < 0) idx = html.indexOf(r.tag + '&nbsp;' + esc(r.text));
            if (idx < 0) {
                const looseNeedle = r.tag.toLowerCase() + ' ' + r.text;
                idx = html.toLowerCase().indexOf(looseNeedle);
            }
            if (idx < 0) continue;

            let end = idx + needle.length;
            if (html.indexOf(needleEsc, idx) === idx) end = idx + needleEsc.length;
            const after = html.slice(end, end + 15);
            const brMatch = after.match(/^\s*<br\s*\/?>/);
            if (brMatch) end += brMatch[0].length;

            html = html.slice(0, idx) + r.bubble + html.slice(end);
            changed = true;
        }

        if (changed) $target.html(html);
    }

    function initializeScript() {
        if (!window.TavernHelper || !window.tavern_events || typeof window.eventOn !== 'function') { setTimeout(initializeScript, 200); return; }
        TH = window.TavernHelper;
        const ev = window.tavern_events;
        if (!$('#' + CSS_ID).length) $('head').append('<style id="' + CSS_ID + '">' + CSS + '</style>');
        window.eventOn(ev.CHARACTER_MESSAGE_RENDERED, renderVisual);
        window.eventOn(ev.USER_MESSAGE_RENDERED, renderVisual);
        window.eventOn(ev.MESSAGE_EDITED, function(id) { setTimeout(function(){ renderVisual(id); }, 100); });
        window.eventOn(ev.MESSAGE_UPDATED, function(id) { setTimeout(function(){ renderVisual(id); }, 100); });
        window.eventOn(ev.MESSAGE_SWIPED, function(id) { setTimeout(function(){ renderVisual(id); }, 100); });
        const scan = function() { $('.mes').each(function() { const id = $(this).attr('mesid'); if (id) renderVisual(Number(id)); }); };
        scan();
        window.eventOn(ev.CHAT_CHANGED, function(){ setTimeout(scan, 500); });
        if (ev.MORE_MESSAGES_LOADED) window.eventOn(ev.MORE_MESSAGES_LOADED, scan);
        console.log('[MsgBubbles] init OK');
    }
    $(document).ready(initializeScript);
})();
